#include<bits/stdc++.h>
using namespace std;

char a[205];

int main()
{
	int len,n,s=0,i,j;
	scanf("%d",&n);
	scanf("%s",a);
	len=strlen(a);
	for(i=0;i<=len-1;i++)
	{
		if(a[i]=='V'&&a[i+1]=='K')
		{
			s++;
			a[i]='a';
			a[i+1]='a';
		}
	}
	for(j=0;j<=len-1;j++)
	{
		if(a[j]=='V'&&a[j+1]=='V'||a[j]=='K'&&a[j+1]=='K')
		{
			s++;
			break;
		}
	}
	printf("%d",s);
	return 0;
}
